export function nextGeneration(liveCells: Array<[number, number]>): Array<[number, number]> {
  if (liveCells.length === 0) {
    return [];
  }

  // Count neighbors for a specific cell
  const countNeighbors = (x: number, y: number): number => {
    let count = 0;
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        if (dx === 0 && dy === 0) continue;
        if (liveCells.some(([cx, cy]) => cx === x + dx && cy === y + dy)) {
          count++;
        }
      }
    }
    return count;
  };

  // Get all cells to check: live cells + their neighbors
  const cellsToCheck = new Set<string>();
  for (const [x, y] of liveCells) {
    for (let dx = -1; dx <= 1; dx++) {
      for (let dy = -1; dy <= 1; dy++) {
        cellsToCheck.add(`${x + dx},${y + dy}`);
      }
    }
  }

  // Build next generation
  const nextGen: Array<[number, number]> = [];
  for (const cellStr of cellsToCheck) {
    const [x, y] = cellStr.split(",").map(Number);
    const isAlive = liveCells.some(([cx, cy]) => cx === x && cy === y);
    const neighbors = countNeighbors(x, y);

    const shouldSurvive = isAlive && (neighbors === 2 || neighbors === 3);
    const shouldBeReproduced = !isAlive && neighbors === 3;

    if (shouldSurvive || shouldBeReproduced) {
      nextGen.push([x, y]);
    }
  }

  // Sort for consistent output
  nextGen.sort((a, b) => a[0] !== b[0] ? a[0] - b[0] : a[1] - b[1]);
  return nextGen;
}

